#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MOD 1000000007
#define MAXN 25
#define MAXC 1000000000

int N, C;
int adj[MAXN][MAXN];
int memo[MAXN][MAXC];

int dp(int face, int color) {
    if (face == N) return 1;
    if (memo[face][color] != -1) return memo[face][color];
    int res = 0;
    for (int i = 0; i < C; i++) {
        int valid = 1;
        for (int j = 0; j < N; j++) {
            if (adj[face][j] && i == color) valid = 0;
        }
        if (valid) res = (res + dp(face + 1, i)) % MOD;
    }
    return memo[face][color] = res;
}

int main() {
    scanf("%d %d", &N, &C);
    for (int i = 0; i < N; i++) {
        int k;
        scanf("%d", &k);
        for (int j = 0; j < k; j++) {
            int x;
            scanf("%d", &x);
            adj[i][x - 1] = 1;
        }
    }
    memset(memo, -1, sizeof(memo));
    printf("%d\n", dp(0, 0));
    return 0;
}

