import java.util.Scanner;
import java.util.HashMap;

public class Main {
    static final int MOD = 1000000007;
    static final int MAXN = 25;
    static final int MAXC = 1000000000;
    static int N, C;
    static int[][] adj;
    static HashMap<Integer, Integer> memo;

    public static int dp(int face, int color) {
        if (face == N) return 1;
        if (memo.containsKey(face * MAXC + color)) return memo.get(face * MAXC + color);
        int res = 0;
        for (int i = 0; i < C; i++) {
            int valid = 1;
            for (int j = 0; j < N; j++) {
                if (adj[face][j] == 1 && i == color) valid = 0;
            }
            if (valid) res = (res + dp(face + 1, i)) % MOD;
        }
        return memo.put(face * MAXC + color, res);
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        N = sc.nextInt();
        C = sc.nextInt();
        adj = new int[N][N];
        for (int i = 0; i < N; i++) {
            int k = sc.nextInt();
            for (int j = 0; j < k; j++) {
                int x = sc.nextInt();
                adj[i][x - 1] = 1;
            }
        }
        memo = new HashMap<>();
        System.out.println(dp(0, 0));
    }
}

